<template><div class="user-profile"><div class="profile-toolbar"><el-button icon="el-icon-arrow-left" size="small" @click="goBack">Back</el-button></div><div class="profile-header"><div class="avatar-section"><el-avatar :size="80" :src="userAvatar"></el-avatar><input ref="avatarInput" class="avatar-input" type="file" accept="image/png,image/jpeg,image/webp" @change="handleAvatarChange"><el-button size="mini" @click="chooseAvatar">Change Avatar</el-button></div><div class="profile-info"><h2>{{profileForm.name||userId}}</h2><span class="user-role-tag">{{userRole==='student'?'Student':'Teacher'}}</span></div></div><el-divider></el-divider><el-form :model="profileForm" label-width="90px"><el-form-item label="Name"><el-input v-model="profileForm.name"></el-input></el-form-item><el-form-item label="Password"><el-input v-model="profileForm.password" type="password" placeholder="Leave blank"></el-input></el-form-item><el-form-item label="Gender"><el-radio-group v-model="profileForm.gender"><el-radio label="male">M</el-radio><el-radio label="female">F</el-radio></el-radio-group></el-form-item><el-form-item label="Degree"><el-select v-model="profileForm.title" style="width:100%"><el-option label="Doctor" value="doctor"></el-option><el-option label="Master" value="master"></el-option><el-option label="Bachelor" value="bachelor"></el-option></el-select></el-form-item><el-form-item label="Email"><el-input v-model="profileForm.email"></el-input></el-form-item><el-form-item label="Phone"><el-input v-model="profileForm.phone"></el-input></el-form-item><el-form-item label="Direction"><el-select v-model="profileForm.targetDirection" style="width:100%"><el-option label="AI Basics" value="AI Basics"></el-option><el-option label="Python" value="Python"></el-option><el-option label="ML/DL" value="ML/DL"></el-option><el-option label="CS Basics" value="CS Basics"></el-option><el-option label="Mechanical" value="Mechanical"></el-option></el-select></el-form-item><el-form-item label="Goal"><el-input type="textarea" v-model="profileForm.research" rows="2"></el-input></el-form-item><el-form-item><el-button type="primary" @click="saveProfile">Save</el-button><el-button @click="resetForm">Reset</el-button></el-form-item></el-form></div></template><script>import axios from 'axios';export default{name:'UserProfile',data(){return{userAvatar:'',defaultAvatar:'/yu-avatar.png',userId:'',userRole:'student',profileForm:{name:'',gender:'',password:'',title:'',email:'',phone:'',research:'',targetDirection:''}}},created(){const u=JSON.parse(localStorage.getItem('user'));if(u){this.userId=u.userId;this.applyLocal(u);this.fetchProfile(u.userId)}},methods:{goBack(){this.$router.back()},chooseAvatar(){this.$refs.avatarInput.click()},handleAvatarChange(e){const f=e.target.files[0];if(!f||f.size>2*1024*1024){this.$message.error('Too large');return};const r=new FileReader();r.onload=()=>{this.userAvatar=r.result};r.readAsDataURL(f);e.target.value=''},applyLocal(u){this.userAvatar=u.avatar||this.defaultAvatar;this.profileForm.name=u.username||'';this.profileForm.gender=u.gender||'male';this.profileForm.title=u.title||'bachelor';this.profileForm.email=u.email||'';this.profileForm.phone=u.phone||u.userId||'';this.profileForm.targetDirection=u.targetDirection||''},async fetchProfile(uid){try{const r=await axios.get('/api/users/profile/'+uid);if(r.data?.success&&r.data.data){const d=r.data.data;if(d.username)this.profileForm.name=d.username;if(d.gender)this.profileForm.gender=d.gender;if(d.title)this.profileForm.title=d.title;if(d.email)this.profileForm.email=d.email;if(d.phone)this.profileForm.phone=d.phone}}catch(e){}},async saveProfile(){try{const r=await axios.post('/api/users/update',{userId:this.userId,username:this.profileForm.name,gender:this.profileForm.gender,title:this.profileForm.title,email:this.profileForm.email,phone:this.profileForm.phone,research:this.profileForm.research,targetDirection:this.profileForm.targetDirection,role:this.userRole,password:this.profileForm.password||undefined});if(r.data?.success){const u=JSON.parse(localStorage.getItem('user')||'{}');Object.assign(u,this.profileForm);localStorage.setItem('user',JSON.stringify(u));this.$message.success('Saved');this.profileForm.password=''}else{this.$message.error(r.data?.message||'Failed')}}catch(e){this.$message.error('Error')}},resetForm(){const u=JSON.parse(localStorage.getItem('user'));if(u)this.applyLocal(u)}}}</script><style scoped>.user-profile{max-width:520px;margin:0 auto;padding:24px 20px}.profile-toolbar{margin-bottom:16px}.profile-header{display:flex;align-items:center;gap:20px;padding:8px 0 16px}.avatar-section{text-align:center}.avatar-input{display:none}.profile-info h2{font-size:20px;font-weight:600;color:#1e293b;margin:0 0 4px}.user-role-tag{font-size:12px;padding:2px 10px;border-radius:10px;background:#ede9fe;color:#7c3aed}</style>